const STORAGE_KEY = 'fundflow_tracked_items';

export const getTrackedItems = (): TrackedItem[] => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    console.error("Error parsing tracked items", e);
    return [];
  }
};

export const addTrackedItem = (item: TrackedItem) => {
  const items = getTrackedItems();
  // Prevent duplicates
  if (!items.find(i => i.id === item.id && i.type === item.type)) {
    const newItems = [...items, item];
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
  }
};

export const removeTrackedItem = (id: string, type: EntityType) => {
  const items = getTrackedItems();
  const newItems = items.filter(i => !(i.id === id && i.type === type));
  localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
};

export const isTracked = (id: string, type: EntityType): boolean => {
  const items = getTrackedItems();
  return !!items.find(i => i.id === id && i.type === type);
};

// Helper to generate the specific config for a stock
export const generateInsightConfig = (symbol: string, pk: string, slug: string): InsightsConfig[] => {
  // Configs that require parsing/filtering
  const parsingReqMap: Record<string, boolean> = {
    "PE": true, "DetailledPE": true, "Technical": false, "MFHoldings": true,
    "QuaterlyHoldings": true, "Bulk/Block Deals": true, "Insider/SAST Deals": false, "FinancialInsights": false
  };

  const filterReqMap: Record<string, boolean> = {
    "PE": false, "DetailledPE": false, "Technical": false, "MFHoldings": false,
    "QuaterlyHoldings": false, "Bulk/Block Deals": false, "Insider/SAST Deals": true, "FinancialInsights": false
  };

  // Special URL adjustments per indicator if needed (e.g., DetailledPE might follow a slightly diff pattern)

  return INSIGHTS_TEMPLATE.map(t => {
    let finalUrl = t.url
      .replace(/stockpk/g, pk)
      .replace(/symbol/g, symbol) // Case sensitive replacement often required by APIs, assuming symbol is correct case
      .replace(/stockslugname/g, slug);

    // Fix for DetailledPE specific URL pattern in template if it differs
    if (t.indicatorName === 'DetailledPE') {
       finalUrl = `https://trendlyne.com/equity/${pk}/${symbol}/`;
    }

    return {
      ...t,
      url: finalUrl,
      geminiParsingReq: parsingReqMap[t.indicatorName] || false,
      filterReq: filterReqMap[t.indicatorName] || false,
    };
  });
};

