        htmlContent = htmlData.join(" ");
    } else if (htmlData && typeof htmlData === 'object') {
        htmlContent = htmlData.rawValue || JSON.stringify(htmlData);
    }

    if (!htmlContent) throw new Error("No HTML content received for Price");

    // Pass to Gemini for Parsing
    return await extractStockDataFromHtml(htmlContent);

  } catch (error) {
    console.error("Error fetching Live Stock Price:", error);
    return null;
  }
};

// --- Real-time Mutual Fund Holdings Fetcher ---

export const fetchMutualFundHoldingsForStock = async (symbol: string): Promise<StockMFAnalysis | null> => {
  try {
    const pkUrl = `https://trendlyne.com/equity/${symbol}/stock-page/`;

    // 1. Get Stock PK
    const pkData = await fetchFromProxy(pkUrl, { attribute: 'data-stock-pk' });
    console.log("Stock PK Response:", pkData);

    let stockPk = pkData;
    if (typeof pkData === 'object' && pkData !== null) {
       stockPk = pkData.rawValue || (Array.isArray(pkData) ? pkData[0] : null);
    }
    if (!stockPk) throw new Error("Could not fetch Stock PK");

    // 2. Get Stock Slug
    const slugData = await fetchFromProxy(pkUrl, { attribute: 'data-stockslugname' });
    console.log("Stock Slug Response:", slugData);

    let stockSlug = slugData;
    if (typeof slugData === 'object' && slugData !== null) {
        stockSlug = slugData.rawValue || (Array.isArray(slugData) ? slugData[0] : null);
    }
    if (!stockSlug) throw new Error("Could not fetch Stock Slug");

    // 3. Get Holdings Table
    const holdingsUrl = `https://trendlyne.com/equity/monthly-mutual-fund-share-holding/${stockPk}/${symbol}/latest/${stockSlug}/prune-etf/`;

    const rawHoldingsData = await fetchFromProxy(holdingsUrl, {
      attribute: 'class',
      attributeValue: 'table tl-dataTable JS_autoDataTables JS_export_btn full-width',
      tagName: 'table'
    });

    console.log("Raw Holdings Response:", rawHoldingsData);

    // Robust check for response structure
    let dataToParse = rawHoldingsData;
    if (!Array.isArray(rawHoldingsData)) {
         if (rawHoldingsData && Array.isArray(rawHoldingsData.data)) {
             dataToParse = rawHoldingsData.data;
         } else {
             // It might be that the proxy returns HTML string for table instead of JSON array. 
             // We can check if dataToParse is string. If so, we can't parse it easily without Gemini or Cheerio.
             // But for now, let's assume if it fails array check, it's null.
             console.warn("Expected array for holdings data but got:", rawHoldingsData);
             return null;
         }
    }

    // 4. Parse Data
    const mfHoldings: MutualFundHolding[] = dataToParse.map((item: any) => {
      const mfTotal = item["MF_Total:"];
      const fundName = mfTotal?.text || "Unknown Fund";
      const fundUrl = mfTotal?.href || "";
      const matches = fundUrl.match(/\d+/g);
      const mfPk = matches ? Number(matches[matches.length - 1]) : null;
      const historyUrl = `https://trendlyne.com/mutual-fund/holding-history/${mfPk}/${stockPk}`;
      console.log(historyUrl);
      // Extract dynamic month keys
      const history: MFHoldingHistory[] = [];
      const keys = Object.keys(item);

      const monthMap = new Map<string, Partial<MFHoldingHistory>>();

      keys.forEach(key => {
        // Regex to match "Dec-2025" pattern at start of key
        const match = key.match(/^([A-Za-z]{3}-\d{4})_(.+)$/);
        if (match) {
          const month = match[1];
          const type = match[2]; 

          if (!monthMap.has(month)) {
            monthMap.set(month, { month });
          }
          const entry = monthMap.get(month)!;

          if (type.includes("Shares Held")) {
            entry.sharesHeld = parseInt(String(item[key]).replace(/,/g, ''), 10) || 0;
          } else if (type.includes("AUM (Cr)")) {
            entry.aum = parseFloat(String(item[key])) || 0;
          } else if (type.includes("Month Change %")) {
            entry.changePercent = parseFloat(String(item[key]).replace('%', '')) || 0;
          } else if (type.includes("Month Change")) {
             entry.change = parseInt(String(item[key]).replace(/,/g, ''), 10) || 0;
          } else if (type.includes("Hold %") || type.includes("AUM %")) {
             entry.aumPercent = parseFloat(String(item[key]).replace('%', '')) || 0;
          }
        }
      });

      const historyArr = Array.from(monthMap.values()) as MFHoldingHistory[];
      historyArr.sort((a, b) => new Date(b.month).getTime() - new Date(a.month).getTime());

      return {
        fundName,
        fundUrl,
        latest: historyArr[0] || null,
        history: historyArr,
        historyUrl
      };
    });

    // 5. Aggregate History for Graph
    const aggMap = new Map<string, number>();
    mfHoldings.forEach(fund => {
      fund.history.forEach(h => {
        const current = aggMap.get(h.month) || 0;
        const shares = isNaN(h.sharesHeld) ? 0 : h.sharesHeld;
        aggMap.set(h.month, current + shares);
      });
    });

    const aggregateHistory = Array.from(aggMap.entries())
      .map(([month, totalShares]) => ({ month, totalShares }))
      .sort((a, b) => new Date(a.month).getTime() - new Date(b.month).getTime());

    return {
      stockSymbol: symbol,
      holdings: mfHoldings,
      aggregateHistory,
      sourceUrl: holdingsUrl
    };

  } catch (error) {
    console.error("Error fetching MF Holdings:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Loader2, CheckCircle, AlertCircle, RefreshCw, ChevronDown, ChevronUp } from 'lucide-react';
import { TrackedItem } from '../../services/trackingStorage';
import { initiateBulkInsightExtraction, pollBulkInsightStatus } from '../../services/dataService';
import { processRawInsightData } from '../../services/geminiService';
import { PollStatusResponse, InsightResultItem } from '../../types/trackingTypes';

interface BulkInsightManagerProps {
  items: TrackedItem[];
  pollInterval?: number; // ms, default 10000
}

const BulkInsightManager: React.FC<BulkInsightManagerProps> = ({ items, pollInterval = 10000 }) => {
  const [requestId, setRequestId] = useState<string | null>(null);
  const [status, setStatus] = useState<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>('idle');
  const [progress, setProgress] = useState({ completed: 0, total: 0 });
  const [results, setResults] = useState<Record<string, InsightResultItem[]>>({});
  const [expandedSymbol, setExpandedSymbol] = useState<string | null>(null);

  // Track processed items to avoid re-parsing
  const processedItemsRef = useRef<Set<string>>(new Set());

  const startExtraction = async () => {
    // Filter only STOCKs for this API
    const stockSymbols = items.filter(i => i.type === 'STOCK').map(i => i.id);

    if (stockSymbols.length === 0) return;

    setStatus('initializing');
    setProgress({ completed: 0, total: stockSymbols.length });
    setResults({});
    processedItemsRef.current.clear();

    const response = await initiateBulkInsightExtraction(stockSymbols);

    if (response && response.requestId) {
      setRequestId(response.requestId);
      setStatus('polling');
      setProgress({ completed: 0, total: response.totalStocks });
    } else {
      setStatus('error');
    }
  };

  useEffect(() => {
    let intervalId: NodeJS.Timeout;

    const poll = async () => {
      if (!requestId || status !== 'polling') return;

      const data = await pollBulkInsightStatus(requestId);

      if (data) {
        setProgress({ completed: data.completedStocks, total: data.totalStocks });

        // Merge results and process Gemini requests
        await handleNewResults(data);

        if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks === data.totalStocks)) {
          setStatus('completed');
          setRequestId(null); // Stop polling
        }
      }
    };

    if (status === 'polling') {
      poll(); // Immediate poll
      intervalId = setInterval(poll, pollInterval);
    }

    return () => clearInterval(intervalId);
  }, [requestId, status, pollInterval]);

  const handleNewResults = async (data: PollStatusResponse) => {
    const updatedResults = { ...results };
    let hasUpdates = false;

    for (const [symbol, items] of Object.entries(data.results)) {
      if (!updatedResults[symbol]) updatedResults[symbol] = [];

      for (const item of items) {
        const uniqueKey = `${symbol}-${item.indicatorName}`;

        // If we haven't processed this item yet
        if (!processedItemsRef.current.has(uniqueKey)) {
          processedItemsRef.current.add(uniqueKey);

          let processedItem = { ...item };

          // Apply Gemini Parsing if needed
          if (item.success && item.geminiParsingReq && item.data) {
             const rawText = typeof item.data === 'string' ? item.data : JSON.stringify(item.data);
             // Non-blocking update: trigger async parse but don't hold up the loop
             processRawInsightData(rawText, item.geminiPrompt, item.indicatorName).then(parsed => {
                 setResults(prev => {
                     const next = { ...prev };
                     const stockItems = next[symbol] || [];
                     const index = stockItems.findIndex(i => i.indicatorName === item.indicatorName);
                     if (index !== -1) {
                         stockItems[index] = { ...stockItems[index], processedContent: parsed };
                     }
                     return next;
                 });
             });
             // Set placeholder while loading
             processedItem.processedContent = "Analyzing with AI...";
          } else if (item.success) {
             // For JSON data that doesn't need AI, just store it nicely
             processedItem.processedContent = item.data;
          }

          updatedResults[symbol] = [...updatedResults[symbol].filter(i => i.indicatorName !== item.indicatorName), processedItem];
          hasUpdates = true;
        }
      }
    }

    if (hasUpdates) {
      setResults(updatedResults);
    }
  };

  const toggleExpand = (symbol: string) => {
    setExpandedSymbol(expandedSymbol === symbol ? null : symbol);
  };

  const renderContent = (item: InsightResultItem) => {
      if (!item.success) return <span className="text-red-500 text-sm">Failed to fetch data.</span>;

      if (item.geminiParsingReq) {
          return (
              <div className="text-sm text-gray-700 bg-indigo-50/50 p-3 rounded-md">
                  {item.processedContent === "Analyzing with AI..." ? (
                      <span className="flex items-center gap-2 text-indigo-500"><Loader2 size={12} className="animate-spin"/> AI Analyzing...</span>
                  ) : (
                      item.processedContent
                  )}
              </div>
          );
      }

      // If it's a JSON object (like FinancialInsights usually returns)
      if (typeof item.data === 'object') {
          return (
              <div className="text-xs font-mono text-gray-600 bg-gray-50 p-2 rounded overflow-auto max-h-32">
                  <pre>{JSON.stringify(item.data, null, 2)}</pre>
              </div>
          );
      }

      return <div className="text-xs text-gray-500 truncate" title={String(item.data)}>Raw Data Loaded</div>;
  };

  if (items.filter(i => i.type === 'STOCK').length === 0) return null;

  return (
    <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
      <div className="p-4 bg-gray-50 border-b border-gray-200 flex items-center justify-between">
        <div>
            <h3 className="font-semibold text-gray-800">Fundamental Analysis</h3>
            <p className="text-xs text-gray-500">Deep dive into Valuation, Holdings & Deals</p>
        </div>

        {status === 'idle' || status === 'completed' || status === 'error' ? (
            <button 
                onClick={startExtraction}
                className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white text-sm rounded-lg hover:bg-indigo-700 transition-colors"
            >
                {status === 'idle' ? 'Analyze Portfolio' : 'Re-Analyze'}
                <RefreshCw size={14} />
            </button>
        ) : (
            <div className="flex items-center gap-3">
                <span className="text-xs font-medium text-indigo-600">
                    {progress.completed}/{progress.total} Processed
                </span>
                <Loader2 size={18} className="animate-spin text-indigo-600" />
            </div>
        )}
      </div>

      <div className="divide-y divide-gray-100">
         {Object.keys(results).length === 0 && status !== 'polling' && status !== 'initializing' && (
             <div className="p-8 text-center text-gray-400 text-sm">
                 Click "Analyze Portfolio" to fetch deep insights for your tracked stocks.
             </div>
         )}

         {Object.entries(results).map(([symbol, indicators]) => (
             <div key={symbol} className="bg-white">
                 <button 
                    onClick={() => toggleExpand(symbol)}
                    className="w-full flex items-center justify-between p-4 hover:bg-gray-50 transition-colors"
                 >
                     <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-700 flex items-center justify-center font-bold text-xs">
                             {symbol[0]}
                         </div>
                         <div className="text-left">
                             <div className="font-medium text-gray-900">{symbol}</div>
                             <div className="text-xs text-gray-500">{indicators.length} indicators loaded</div>
                         </div>
                     </div>
                     {expandedSymbol === symbol ? <ChevronUp size={16} className="text-gray-400"/> : <ChevronDown size={16} className="text-gray-400"/>}
                 </button>

                 {expandedSymbol === symbol && (
                     <div className="p-4 bg-gray-50/50 grid grid-cols-1 md:grid-cols-2 gap-4 border-t border-gray-100">
                         {indicators.map((ind, idx) => (
                             <div key={idx} className="bg-white p-3 rounded-lg border border-gray-200 shadow-sm">
                                 <div className="flex items-center gap-2 mb-2">
                                     {ind.success ? <CheckCircle size={14} className="text-green-500"/> : <AlertCircle size={14} className="text-red-500"/>}
                                     <span className="font-semibold text-xs text-gray-700 uppercase">{ind.indicatorName}</span>
                                 </div>
                                 {renderContent(ind)}
                             </div>
                         ))}
                     </div>
                 )}
             </div>
         ))}
      </div>
    </div>
  );
};

export default BulkInsightManager;

import React, { useState, useMemo, useEffect } from 'react';
import { Search, Loader2, RefreshCw, Database, Sparkles, ExternalLink, BarChart2 } from 'lucide-react';
import DashboardSidebar from './DashboardSidebar';
import InsightCard from './InsightCard';
import DataStream from './DataStream';
import BulkInsightManager from './BulkInsightManager';
import { getTrackedItems, TrackedItem } from '../../services/trackingStorage';
import { fetchMarketInsights } from '../../services/geminiService';
import { Insight } from '../../types/trackingTypes';
import { FundSearchResult } from '../../types';

interface TrackingDashboardProps {
  onSelectStock: (symbol: string, name: string) => void;
  onSelectFund: (fund: FundSearchResult) => void;
}

const TrackingDashboard: React.FC<TrackingDashboardProps> = ({ onSelectStock, onSelectFund }) => {
  const [selectedType, setSelectedType] = useState<'ALL' | 'STOCK' | 'MF'>('ALL');
  const [selectedEntityId, setSelectedEntityId] = useState<string | 'ALL'>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  // Tabs State
  const [activeStreamTab, setActiveStreamTab] = useState<'DATA' | 'AI' | 'DEEP_DIVE'>('DATA');

  // Real Data State
  const [entities, setEntities] = useState<TrackedItem[]>([]);
  const [insights, setInsights] = useState<Insight[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Track if we have fetched insights for the current view context
  const [insightsFetched, setInsightsFetched] = useState(false);

  // Load Tracked Items on mount
  useEffect(() => {
    const loadedEntities = getTrackedItems();
    setEntities(loadedEntities);
  }, []);

  // Filter Entities based on selection
  const visibleEntities = useMemo(() => {
     if (selectedEntityId !== 'ALL') {
         return entities.filter(e => e.id === selectedEntityId);
     }
     if (selectedType !== 'ALL') {
         return entities.filter(e => e.type === selectedType);
     }
     return entities;
  }, [entities, selectedEntityId, selectedType]);

  const fetchInsights = async () => {
     if (visibleEntities.length === 0) return;

     setLoadingInsights(true);
     try {
         const data = await fetchMarketInsights(visibleEntities);
         setInsights(data);
         setInsightsFetched(true);
     } catch (err) {
         console.error(err);
     } finally {
         setLoadingInsights(false);
     }
  };

  // Reset insights fetched state when selection changes
  useEffect(() => {
      setInsightsFetched(false);
      setInsights([]);

      if (activeStreamTab === 'AI') {
          const timer = setTimeout(() => {
             // Logic to auto-fetch could go here
          }, 100);
          return () => clearTimeout(timer);
      }
  }, [selectedEntityId, selectedType]);

  // Effect to handle AI Tab activation or Context Switch while Active
  useEffect(() => {
      if (activeStreamTab === 'AI' && !insightsFetched && !loadingInsights && visibleEntities.length > 0) {
          fetchInsights();
      }
  }, [activeStreamTab, visibleEntities, insightsFetched]);


  // Filter Insights for Display
  const filteredInsights = useMemo(() => {
    let filtered = insights;

    // Filter by Search Query
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        filtered = filtered.filter(i => 
        i.title.toLowerCase().includes(lowerQ) || 
        i.content.toLowerCase().includes(lowerQ)
        );
    }

    // Enrich with Entity Data
    return filtered.map(item => {
        const entity = entities.find(e => e.id === item.entityId);
        return { ...item, entityName: entity?.name || 'Unknown', entitySymbol: entity?.symbol };
    }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  }, [insights, entities, searchQuery]);

  const currentEntity = entities.find(e => e.id === selectedEntityId);
  const currentEntityName = selectedEntityId === 'ALL' 
    ? 'All Tracked Assets' 
    : currentEntity?.name;

  const handleHeaderClick = () => {
    if (selectedEntityId === 'ALL' || !currentEntity) return;

    if (currentEntity.type === 'STOCK') {
        onSelectStock(currentEntity.id, currentEntity.name);
    } else {
        onSelectFund({
            name: currentEntity.name,
            url: currentEntity.url || '',
            pk: !isNaN(Number(currentEntity.id)) ? Number(currentEntity.id) : undefined
        });
    }
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 animate-fade-in">
      {/* Sidebar Navigation */}
