import React, { useState, useEffect, useRef } from 'react';
import { Loader2, CheckCircle, AlertCircle, RefreshCw, ChevronDown, ChevronUp } from 'lucide-react';
import { TrackedItem } from '../../services/trackingStorage';
import { initiateBulkInsightExtraction, pollBulkInsightStatus } from '../../services/dataService';
import { processRawInsightData } from '../../services/geminiService';
import { PollStatusResponse, InsightResultItem } from '../../types/trackingTypes';

interface BulkInsightManagerProps {
  items: TrackedItem[];
  pollInterval?: number; // ms, default 10000
}

const BulkInsightManager: React.FC<BulkInsightManagerProps> = ({ items, pollInterval = 10000 }) => {
  const [requestId, setRequestId] = useState<string | null>(null);
  const [status, setStatus] = useState<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>('idle');
  const [progress, setProgress] = useState({ completed: 0, total: 0 });
  const [results, setResults] = useState<Record<string, InsightResultItem[]>>({});
  const [expandedSymbol, setExpandedSymbol] = useState<string | null>(null);

  // Track processed items to avoid re-parsing
  const processedItemsRef = useRef<Set<string>>(new Set());

  const startExtraction = async () => {
    // Filter only STOCKs for this API
    const stockSymbols = items.filter(i => i.type === 'STOCK').map(i => i.id);

    if (stockSymbols.length === 0) return;

    setStatus('initializing');
    setProgress({ completed: 0, total: stockSymbols.length });
    setResults({});
    processedItemsRef.current.clear();

    const response = await initiateBulkInsightExtraction(stockSymbols);

    if (response && response.requestId) {
      setRequestId(response.requestId);
      setStatus('polling');
      setProgress({ completed: 0, total: response.totalStocks });
    } else {
      setStatus('error');
    }
  };

  useEffect(() => {
    let intervalId: ReturnType<typeof setInterval>;

    const poll = async () => {
      if (!requestId || status !== 'polling') return;

      const data = await pollBulkInsightStatus(requestId);

      if (data) {
        setProgress({ completed: data.completedStocks, total: data.totalStocks });

        // Merge results and process Gemini requests
        await handleNewResults(data);

        if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks === data.totalStocks)) {
          setStatus('completed');
          setRequestId(null); // Stop polling
        }
      }
    };

    if (status === 'polling') {
      poll(); // Immediate poll
      intervalId = setInterval(poll, pollInterval);
    }

    return () => clearInterval(intervalId);
  }, [requestId, status, pollInterval]);

  const handleNewResults = async (data: PollStatusResponse) => {
    const updatedResults = { ...results };
    let hasUpdates = false;

    for (const [symbol, items] of Object.entries(data.results)) {
      if (!updatedResults[symbol]) updatedResults[symbol] = [];

      for (const item of items) {
        const uniqueKey = `${symbol}-${item.indicatorName}`;

        // If we haven't processed this item yet
        if (!processedItemsRef.current.has(uniqueKey)) {
          processedItemsRef.current.add(uniqueKey);

          let processedItem = { ...item };

          // Apply Gemini Parsing if needed
          if (item.success && item.geminiParsingReq && item.data) {
             const rawText = typeof item.data === 'string' ? item.data : JSON.stringify(item.data);
             // Non-blocking update: trigger async parse but don't hold up the loop
             processRawInsightData(rawText, item.geminiPrompt, item.indicatorName).then(parsed => {
                 setResults(prev => {
                     const next = { ...prev };
                     const stockItems = next[symbol] || [];
                     const index = stockItems.findIndex(i => i.indicatorName === item.indicatorName);
                     if (index !== -1) {
                         stockItems[index] = { ...stockItems[index], processedContent: parsed };
                     }
                     return next;
                 });
             });
             // Set placeholder while loading
             processedItem.processedContent = "Analyzing with AI...";
          } else if (item.success) {
             // For JSON data that doesn't need AI, just store it nicely
             processedItem.processedContent = item.data;
          }

          updatedResults[symbol] = [...updatedResults[symbol].filter(i => i.indicatorName !== item.indicatorName), processedItem];
          hasUpdates = true;
        }
      }
    }

    if (hasUpdates) {
      setResults(updatedResults);
    }
  };

  const toggleExpand = (symbol: string) => {
    setExpandedSymbol(expandedSymbol === symbol ? null : symbol);
  };

  const renderContent = (item: InsightResultItem) => {
      if (!item.success) return <span className="text-red-500 text-sm">Failed to fetch data.</span>;

      if (item.geminiParsingReq) {
          return (
              <div className="text-sm text-gray-700 bg-indigo-50/50 p-3 rounded-md">
                  {item.processedContent === "Analyzing with AI..." ? (
                      <span className="flex items-center gap-2 text-indigo-500"><Loader2 size={12} className="animate-spin"/> AI Analyzing...</span>
                  ) : (
                      item.processedContent
                  )}
              </div>
          );
      }

      // If it's a JSON object (like FinancialInsights usually returns)
      if (typeof item.data === 'object') {
          return (
              <div className="text-xs font-mono text-gray-600 bg-gray-50 p-2 rounded overflow-auto max-h-32">
                  <pre>{JSON.stringify(item.data, null, 2)}</pre>
              </div>
          );
      }

      return <div className="text-xs text-gray-500 truncate" title={String(item.data)}>Raw Data Loaded</div>;
  };

  if (items.filter(i => i.type === 'STOCK').length === 0) return null;

  return (
    <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
      <div className="p-4 bg-gray-50 border-b border-gray-200 flex items-center justify-between">
        <div>
            <h3 className="font-semibold text-gray-800">Fundamental Analysis</h3>
            <p className="text-xs text-gray-500">Deep dive into Valuation, Holdings & Deals</p>
        </div>

        {status === 'idle' || status === 'completed' || status === 'error' ? (
            <button 
                onClick={startExtraction}
                className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white text-sm rounded-lg hover:bg-indigo-700 transition-colors"
            >
                {status === 'idle' ? 'Analyze Portfolio' : 'Re-Analyze'}
                <RefreshCw size={14} />
            </button>
        ) : (
            <div className="flex items-center gap-3">
                <span className="text-xs font-medium text-indigo-600">
                    {progress.completed}/{progress.total} Processed
                </span>
                <Loader2 size={18} className="animate-spin text-indigo-600" />
            </div>
        )}
      </div>

      <div className="divide-y divide-gray-100">
         {Object.keys(results).length === 0 && status !== 'polling' && status !== 'initializing' && (
             <div className="p-8 text-center text-gray-400 text-sm">
                 Click "Analyze Portfolio" to fetch deep insights for your tracked stocks.
             </div>
         )}

         {Object.entries(results).map(([symbol, indicators]) => (
             <div key={symbol} className="bg-white">
                 <button 
                    onClick={() => toggleExpand(symbol)}
                    className="w-full flex items-center justify-between p-4 hover:bg-gray-50 transition-colors"
                 >
                     <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-700 flex items-center justify-center font-bold text-xs">
                             {symbol[0]}
                         </div>
                         <div className="text-left">
                             <div className="font-medium text-gray-900">{symbol}</div>
                             <div className="text-xs text-gray-500">{indicators.length} indicators loaded</div>
                         </div>
                     </div>
                     {expandedSymbol === symbol ? <ChevronUp size={16} className="text-gray-400"/> : <ChevronDown size={16} className="text-gray-400"/>}
                 </button>

                 {expandedSymbol === symbol && (
                     <div className="p-4 bg-gray-50/50 grid grid-cols-1 md:grid-cols-2 gap-4 border-t border-gray-100">
                         {indicators.map((ind, idx) => (
                             <div key={idx} className="bg-white p-3 rounded-lg border border-gray-200 shadow-sm">
                                 <div className="flex items-center gap-2 mb-2">
                                     {ind.success ? <CheckCircle size={14} className="text-green-500"/> : <AlertCircle size={14} className="text-red-500"/>}
                                     <span className="font-semibold text-xs text-gray-700 uppercase">{ind.indicatorName}</span>
                                 </div>
                                 {renderContent(ind)}
                             </div>
                         ))}
                     </div>
                 )}
             </div>
         ))}
      </div>
    </div>
  );
};

export default BulkInsightManager;

export type EntityType = 'STOCK' | 'MF';
export type Sentiment = 'POSITIVE' | 'NEGATIVE' | 'NEUTRAL';

export type InsightsConfig = {
  updateType: string;
  indicatorName: string;
  url: string;
  attribute: string;
  attributeValue: string;
  tagName: string;
  geminiParsingReq: boolean;
  geminiPrompt: string;
  filterReq: boolean;
};

export interface TrackedItem {
  id: string; // Symbol for Stocks, PK for MFs
  name: string;
  symbol?: string; // Optional for MFs
  type: EntityType;
  url?: string; // For navigation (e.g. Fund URL)
}

export interface TrackedEntity {
  id: string;
  name: string;
  symbol: string;
  type: EntityType;
  holdings?: number; // Mock user holdings
}

export interface Insight {
  id: string;
  entityId: string;
  title: string;
  content: string;
  date: string;
  sentiment: Sentiment;
  source: string;
  sourceUrl?: string;
}

// --- Bulk API Types ---

export interface StockDataRequestItem {
  Symbol: string;
  data: InsightsConfig[];
}

export interface BulkExtractResponse {
  requestId: string;
  status: string;
  totalStocks: number;
}

export interface InsightResultItem {
  updateType: string;
  indicatorName: string;
  geminiParsingReq: boolean;
  geminiPrompt: string;
  filterReq: boolean;
  url: string;
  success: boolean;
  type: string; // "html" | "json"
  data: string | any; // Raw HTML string or JSON object
  error?: string;
  // Augmented field for frontend state
  processedContent?: string | any; 
}

export interface PollStatusResponse {
  status: 'pending' | 'resolved';
  results: Record<string, InsightResultItem[]>; // Keyed by Symbol
  completedStocks: number;
  totalStocks: number;
  timestamp: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { StockPriceData } from "../types";
import { Insight } from "../types/trackingTypes";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// New function to parse HTML for Stock Data
export const extractStockDataFromHtml = async (html: string): Promise<StockPriceData | null> => {
  try {
    const prompt = `
      Analyze the following HTML content which contains stock market data from a financial website.
      Extract the following information and return it strictly as a JSON object.

      Fields required:
      - "current_price": The current trading price (e.g., "1,234.50").
      - "last_updated": The time/date it was last updated (e.g., "Nov 24, 4:00 PM").
      - "todays_change_direction": "up" if the price increased, "down" if decreased, or "neutral".
      - "todays_change_number": The absolute value change (e.g., "12.50").
      - "todays_change_percentage": The percentage change (e.g., "1.2%").
      - "volume": The trading volume.

      HTML Content:
      ${html}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            current_price: { type: Type.STRING },
            last_updated: { type: Type.STRING },
            todays_change_direction: { type: Type.STRING },
            todays_change_number: { type: Type.STRING },
            todays_change_percentage: { type: Type.STRING },
            volume: { type: Type.STRING }
          },
          required: ['current_price', 'last_updated', 'todays_change_direction', 'todays_change_number', 'todays_change_percentage', 'volume']
        }
      },
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as StockPriceData;

  } catch (error) {
    console.error("Gemini HTML Parsing Error:", error);
    return null;
  }
};

export const searchFunds = async (query: string): Promise<Array<{ name: string; type: string }>> => {
  try {
    const prompt = `Identify up to 5 Indian Mutual Funds that match the search query "${query}". 
    Return the result as a strictly formatted JSON array of objects, where each object has "name" (e.g., SBI Bluechip Fund) and "type" (e.g., Large Cap).`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              type: { type: Type.STRING },
            },
            required: ['name', 'type'],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Fund Search Error:", error);
    return [];
  }
};

export const fetchMarketInsights = async (entities: { id: string, name: string }[]): Promise<Insight[]> => {
  if (entities.length === 0) return [];

  try {
    const names = entities.map(e => e.name).join(", ");
    const prompt = `
      You are a senior financial analyst. Generate 10 high-quality, actionable market insights or news summaries specifically for the following Indian entities: ${names}.

      Guidelines:
      1. Focus on recent quarterly results, major announcements, sector trends (e.g., IT slowdown, Banking liquidity), or regulatory changes.
      2. If specific recent news is unavailable for a specific entity, provide an intelligent analysis of its sector's current outlook that would affect it.
      3. Do NOT invent specific numbers or fake dates. Use general accurate trends if exact recent data is missing.
      4. Sentiment should reflect the likely market reaction.
      5. Provide the URL of the source from where you got the info. 

      Return a JSON array where each object has:
      - title: Headline string (professional style).
      - content: concise summary (max 40 words).
      - sentiment: 'POSITIVE', 'NEGATIVE', or 'NEUTRAL'.
      - entityId: The ID of the entity this insight relates to (choose from: ${entities.map(e => e.id).join(', ')}).
      - source: A plausible source name (e.g., "MoneyControl", "Economic Times", "LiveMint", "CNBC-TV18").
      - sourceUrl: Provide a specific real URL if you know one, otherwise return an empty string.
      - date: ISO date string (use today's date).
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              content: { type: Type.STRING },
              sentiment: { type: Type.STRING },
              entityId: { type: Type.STRING },
              source: { type: Type.STRING },
              sourceUrl: { type: Type.STRING },
              date: { type: Type.STRING }
            },
            required: ['title', 'content', 'sentiment', 'entityId', 'source', 'date']
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    const rawInsights = JSON.parse(text);
    return rawInsights.map((insight: any, index: number) => ({
      ...insight,
      id: `gen-${Date.now()}-${index}`,
      sourceUrl: insight.sourceUrl || `https://www.google.com/search?q=${encodeURIComponent(insight.title + ' ' + insight.source)}`
    }));

  } catch (error) {
    console.error("Gemini Insight Generation Error:", error);
    return [];
  }
};

export const processRawInsightData = async (rawContent: string, instruction: string, indicator: string): Promise<string> => {
  try {
    const prompt = `
      You are an expert financial data analyst. 
      Task: Parse the following raw HTML/Content related to "${indicator}" for a stock.
      Instruction: ${instruction}

      Raw Content:
      ${rawContent.substring(0, 15000)} // Limit context window

      Output strictly simple text or a short summary paragraph. Do not use Markdown formatting unless asked.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Could not process data.";
  } catch (error) {
    console.error(`Gemini Error processing ${indicator}:`, error);
    return "Error processing insight.";
  }
};

// --- Chat Capability ---

export const getChatResponse = async (history: {role: string, parts: {text: string}[]}[], message: string) => {
    try {
        const chat = ai.chats.create({
            model: 'gemini-3-flash-preview',
            history: history,
            config: {
                systemInstruction: "You are a financial assistant. You have been provided with specific data chunks from stock market analysis (Valuations, Deals, Holdings). Answer questions strictly based on this data. If the data isn't there, say so."
            }
        });

        const result = await chat.sendMessage({ message });
        return result.text;
    } catch (e) {
        console.error("Chat error", e);
        return "I'm having trouble connecting to the analysis engine right now.";
    }
}

import React, { useState, useEffect, useRef } from 'react';
import { X, Send, Bot, User, Maximize2, Minimize2 } from 'lucide-react';
import { getChatResponse } from '../../services/geminiService';
import { ChatMessage } from '../../types/trackingTypes';

interface InsightChatbotProps {
  contextData: any[]; // The data from selected cards
  onClose: () => void;
}

const InsightChatbot: React.FC<InsightChatbotProps> = ({ contextData, onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Initialize chat with context
  useEffect(() => {
    const initChat = async () => {
      // Prepare the system context message (hidden from UI)
      const contextString = JSON.stringify(contextData, null, 2);
      const initialPrompt = `Here is the financial data context for the user's query. 
      Data: ${contextString.substring(0, 30000)}... (truncated if too long).

      Please analyze this data and be ready to answer questions about PE Ratios, Holdings, Deals, or Technicals provided in it.`;

      // We add a welcome message from AI
      setMessages([
        {
          id: 'welcome',
          role: 'model',
          text: `I've analyzed the ${contextData.length} selected data points. What would you like to know about these stocks?`,
          timestamp: Date.now()
        }
      ]);
    };
    initChat();
  }, [contextData]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      // Transform messages for API
      const history = [
        {
            role: 'user',
            parts: [{ text: `Context Data: ${JSON.stringify(contextData).substring(0, 30000)}` }]
        },
        {
            role: 'model',
            parts: [{ text: "Understood. I will answer based on this data." }]
        },
        ...messages.map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
        }))
      ];

      const response = await getChatResponse(history, userMsg.text);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`fixed bottom-4 right-4 bg-white rounded-2xl shadow-2xl border border-gray-200 flex flex-col transition-all duration-300 z-50 ${isExpanded ? 'w-[800px] h-[80vh]' : 'w-[400px] h-[600px]'}`}>
      {/* Header */}
      <div className="p-4 bg-indigo-600 text-white rounded-t-2xl flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2">
          <Bot size={20} />
          <span className="font-semibold">Deep Dive Assistant</span>
          <span className="bg-indigo-500 px-2 py-0.5 rounded text-xs text-indigo-100">{contextData.length} Contexts</span>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setIsExpanded(!isExpanded)} className="hover:bg-indigo-500 p-1 rounded">
             {isExpanded ? <Minimize2 size={16}/> : <Maximize2 size={16}/>}
          </button>
          <button onClick={onClose} className="hover:bg-indigo-500 p-1 rounded">
            <X size={18} />
          </button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] rounded-2xl p-3 text-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-br-none' 
                : 'bg-white border border-gray-200 text-gray-800 rounded-bl-none shadow-sm'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-white border border-gray-200 rounded-2xl rounded-bl-none p-3 shadow-sm">
              <div className="flex gap-1">
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 border-t border-gray-100 bg-white rounded-b-2xl">
        <div className="flex gap-2">
          <input
            type="text"
            className="flex-1 border border-gray-300 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
            placeholder="Ask about PE, Holdings, or Deals..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <button 
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="bg-indigo-600 text-white p-2 rounded-xl hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default InsightChatbot;

import React, { useState, useMemo } from 'react';
import { Loader2, CheckCircle, AlertCircle, RefreshCw, MessageSquare, Check, Filter } from 'lucide-react';
import { TrackedItem } from '../../services/trackingStorage';
import { initiateBulkInsightExtraction, pollBulkInsightStatus } from '../../services/dataService';
import { PollStatusResponse, InsightResultItem } from '../../types/trackingTypes';

interface BulkInsightManagerProps {
  items: TrackedItem[];
  // State lifted to parent
  results: Record<string, InsightResultItem[]>;
  setResults: React.Dispatch<React.SetStateAction<Record<string, InsightResultItem[]>>>;
  status: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
  setStatus: React.Dispatch<React.SetStateAction<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>>;
  progress: { completed: number; total: number };
  setProgress: React.Dispatch<React.SetStateAction<{ completed: number; total: number }>>;
  requestId: string | null;
  setRequestId: React.Dispatch<React.SetStateAction<string | null>>;
  onOpenChat: (context: any[]) => void;
}

const BulkInsightManager: React.FC<BulkInsightManagerProps> = ({ 
  items, 
  results, 
  setResults, 
  status, 
  setStatus, 
  progress, 
  setProgress, 
  requestId, 
  setRequestId,
  onOpenChat
}) => {

  // Local UI State
  const [selectedCards, setSelectedCards] = useState<Set<string>>(new Set()); // Key: Symbol-Indicator
  const [filterSymbol, setFilterSymbol] = useState<string>('ALL');
  const [filterIndicator, setFilterIndicator] = useState<string>('ALL');

  // --- Actions ---

  const startExtraction = async () => {
    const stockSymbols = items.filter(i => i.type === 'STOCK').map(i => i.id);
    if (stockSymbols.length === 0) return;

    setStatus('initializing');
    setProgress({ completed: 0, total: stockSymbols.length });

    // Don't clear results immediately if we want to "Refresh" while keeping old data visible
    // But usually for a fresh fetch, we might want to clear or overlay. Let's keep for overlay.

    const response = await initiateBulkInsightExtraction(stockSymbols);

    if (response && response.requestId) {
      setRequestId(response.requestId);
      setStatus('polling');
      setProgress({ completed: 0, total: response.totalStocks });
    } else {
      setStatus('error');
    }
  };

  // --- Polling Logic (Effect is now here but uses props setters) ---
  React.useEffect(() => {
    let intervalId: ReturnType<typeof setInterval>;

    const poll = async () => {
      if (!requestId || status !== 'polling') return;

      const data = await pollBulkInsightStatus(requestId);

      if (data) {
        setProgress({ completed: data.completedStocks, total: data.totalStocks });
        handleNewResults(data);

        if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks === data.totalStocks)) {
          setStatus('completed');
          setRequestId(null);
        }
      }
    };

    if (status === 'polling') {
      poll();
      intervalId = setInterval(poll, 5000);
    }

    return () => clearInterval(intervalId);
  }, [requestId, status]);

  const handleNewResults = (data: PollStatusResponse) => {
    setResults(prev => {
      const next = { ...prev };
      // Deep merge logic: Update specific items without wiping others
      for (const [symbol, newItems] of Object.entries(data.results)) {
        const existingItems = next[symbol] || [];

        // For each new item, replace the old one or add it
        const mergedItems = [...existingItems];
        newItems.forEach(newItem => {
           const index = mergedItems.findIndex(i => i.indicatorName === newItem.indicatorName);
           if (index > -1) {
               mergedItems[index] = newItem;
           } else {
               mergedItems.push(newItem);
           }
        });
        next[symbol] = mergedItems;
      }
      return next;
    });
  };

  // --- Selection Logic ---

  const toggleCardSelection = (symbol: string, indicator: string) => {
      const key = `${symbol}|${indicator}`;
      const newSet = new Set(selectedCards);
      if (newSet.has(key)) newSet.delete(key);
      else newSet.add(key);
      setSelectedCards(newSet);
  };

  const handleAnalyzeSelection = () => {
      const selectedData: any[] = [];

      selectedCards.forEach(key => {
          const [sym, ind] = key.split('|');
          const item = results[sym]?.find(i => i.indicatorName === ind);
          if (item) {
              selectedData.push({ symbol: sym, indicator: ind, data: item.data });
          }
      });

      if (selectedData.length > 0) {
          onOpenChat(selectedData);
      }
  };

  // --- Render Helpers ---

  // Flatten results for grid view
  const flatItems = useMemo(() => {
      const flat: Array<{ symbol: string; item: InsightResultItem }> = [];
      Object.entries(results).forEach(([symbol, indicators]) => {
          indicators.forEach(item => {
              if (
                  (filterSymbol === 'ALL' || filterSymbol === symbol) &&
                  (filterIndicator === 'ALL' || filterIndicator === item.indicatorName)
              ) {
                  flat.push({ symbol, item });
              }
          });
      });
      return flat;
  }, [results, filterSymbol, filterIndicator]);

  const uniqueSymbols = Object.keys(results);
  const uniqueIndicators = Array.from(new Set(Object.values(results).flat().map(i => i.indicatorName)));

  const renderCardContent = (data: any) => {
      if (typeof data === 'string') {
          // If HTML, strip tags for preview or show simplistic view
          if (data.includes('<')) {
              return <div className="text-xs text-gray-400 italic">HTML Content - Click Chat to Analyze</div>;
          }
          return <div className="text-xs text-gray-600 line-clamp-4">{data}</div>;
      }
      if (typeof data === 'object') {
          return (
              <div className="text-[10px] font-mono text-gray-600 bg-gray-50 p-2 rounded overflow-hidden max-h-24">
                  <pre>{JSON.stringify(data, null, 2)}</pre>
              </div>
          );
      }
      return null;
  };

  if (items.filter(i => i.type === 'STOCK').length === 0) return null;

  return (
    <div className="space-y-4">
      {/* Control Bar */}
      <div className="bg-white rounded-xl border border-gray-200 p-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-sm">
         <div className="flex items-center gap-4 w-full md:w-auto">
             {/* Symbol Filter */}
             <div className="relative">
                 <select 
                    className="appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full p-2.5 pr-8"
                    value={filterSymbol}
                    onChange={(e) => setFilterSymbol(e.target.value)}
                 >
                     <option value="ALL">All Stocks</option>
                     {uniqueSymbols.map(s => <option key={s} value={s}>{s}</option>)}
                 </select>
                 <Filter size={14} className="absolute right-3 top-3 text-gray-400 pointer-events-none"/>
             </div>

             {/* Indicator Filter */}
             <div className="relative">
                 <select 
                    className="appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full p-2.5 pr-8"
                    value={filterIndicator}
                    onChange={(e) => setFilterIndicator(e.target.value)}
                 >
                     <option value="ALL">All Indicators</option>
                     {uniqueIndicators.map(i => <option key={i} value={i}>{i}</option>)}
                 </select>
                 <Filter size={14} className="absolute right-3 top-3 text-gray-400 pointer-events-none"/>
             </div>
         </div>

         <div className="flex items-center gap-3 w-full md:w-auto justify-end">
             {selectedCards.size > 0 && (
                 <button 
                    onClick={handleAnalyzeSelection}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-lg hover:bg-indigo-700 transition-colors shadow-sm"
                 >
                     <MessageSquare size={16} />
                     Analyze Selected ({selectedCards.size})
                 </button>
             )}

            {status === 'polling' ? (
                <div className="flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-700 rounded-lg text-sm">
                    <Loader2 size={16} className="animate-spin" />
                    <span>{progress.completed}/{progress.total}</span>
                </div>
            ) : (
                <button 
                    onClick={startExtraction}
                    className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-gray-100 rounded-lg transition-colors border border-transparent hover:border-gray-200"
                    title="Refresh Data"
                >
                    <RefreshCw size={20} />
                </button>
            )}
         </div>
      </div>

      {/* Grid View */}
      {flatItems.length === 0 && status !== 'polling' && status !== 'initializing' && (
          <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
              <p className="text-gray-500">No data available. Click Refresh to start Deep Dive analysis.</p>
          </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {flatItems.map(({ symbol, item }, idx) => {
              const cardKey = `${symbol}|${item.indicatorName}`;
              const isSelected = selectedCards.has(cardKey);

              return (
                  <div 
                    key={idx} 
                    className={`bg-white rounded-xl border transition-all duration-200 flex flex-col ${
                        isSelected ? 'border-indigo-500 shadow-md ring-1 ring-indigo-500' : 'border-gray-200 shadow-sm hover:shadow-md'
                    }`}
                  >
                      <div className="p-3 border-b border-gray-100 flex items-center justify-between bg-gray-50 rounded-t-xl">
                          <div className="flex items-center gap-2">
                              <span className="font-bold text-gray-800 text-sm">{symbol}</span>
                              <span className="text-xs text-gray-400">•</span>
                              <span className="text-xs font-medium text-gray-600 truncate max-w-[100px]" title={item.indicatorName}>
                                  {item.indicatorName}
                              </span>
                          </div>

                          <div className="flex items-center gap-2">
                              {item.success ? <CheckCircle size={14} className="text-green-500"/> : <AlertCircle size={14} className="text-red-500"/>}
                              <button 
                                onClick={() => toggleCardSelection(symbol, item.indicatorName)}
                                className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${
                                    isSelected ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-gray-300 text-transparent hover:border-indigo-400'
                                }`}
                              >
                                  <Check size={12} />
                              </button>
                          </div>
                      </div>

                      <div className="p-3 flex-1 overflow-hidden">
                          {item.success ? renderCardContent(item.data) : <div className="text-red-500 text-xs">Failed to load</div>}
                      </div>

                      {item.success && (
                          <div className="p-2 border-t border-gray-100 flex justify-end">
                              <button 
                                onClick={() => onOpenChat([{ symbol, indicator: item.indicatorName, data: item.data }])}
                                className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                              >
                                  <MessageSquare size={14} />
                                  Ask AI
                              </button>
                          </div>
                      )}
                  </div>
              );
          })}
      </div>
    </div>
  );
};

