import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Loader2, CheckCircle, AlertCircle, RefreshCw, MessageSquare, Check, Filter, LayoutGrid, List, ChevronDown, X } from 'lucide-react';
import { TrackedItem } from '../../services/trackingStorage';
import { initiateBulkInsightExtraction, pollBulkInsightStatus } from '../../services/dataService';
import { PollStatusResponse, InsightResultItem } from '../../types/trackingTypes';

interface BulkInsightManagerProps {
  items: TrackedItem[];
  // State lifted to parent
  results: Record<string, InsightResultItem[]>;
  setResults: React.Dispatch<React.SetStateAction<Record<string, InsightResultItem[]>>>;
  status: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
  setStatus: React.Dispatch<React.SetStateAction<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>>;
  progress: { completed: number; total: number };
  setProgress: React.Dispatch<React.SetStateAction<{ completed: number; total: number }>>;
  requestId: string | null;
  setRequestId: React.Dispatch<React.SetStateAction<string | null>>;
  onOpenChat: (context: any[]) => void;
}

// --- MultiSelect Component ---
interface MultiSelectProps {
    label: string;
    options: string[];
    selected: string[];
    onChange: (selected: string[]) => void;
}

const MultiSelect: React.FC<MultiSelectProps> = ({ label, options, selected, onChange }) => {
    const [isOpen, setIsOpen] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const toggleOption = (option: string) => {
        if (selected.includes(option)) {
            onChange(selected.filter(s => s !== option));
        } else {
            onChange([...selected, option]);
        }
    };

    return (
        <div className="relative flex-1 min-w-[150px]" ref={containerRef}>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center justify-between w-full bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg px-3 py-2 hover:bg-white hover:border-gray-300 transition-colors"
            >
                <span className="truncate">
                    {selected.length === 0 ? `All ${label}` : `${selected.length} ${label} selected`}
                </span>
                <ChevronDown size={14} className="text-gray-400 ml-2" />
            </button>

            {isOpen && (
                <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-20 max-h-60 overflow-y-auto p-1">
                    <div 
                        onClick={() => onChange([])}
                        className={`px-3 py-2 text-sm rounded-md cursor-pointer hover:bg-indigo-50 flex items-center justify-between ${selected.length === 0 ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-700'}`}
                    >
                        <span>All {label}</span>
                        {selected.length === 0 && <Check size={14} />}
                    </div>
                    {options.map(opt => (
                        <div 
                            key={opt}
                            onClick={() => toggleOption(opt)}
                            className={`px-3 py-2 text-sm rounded-md cursor-pointer hover:bg-gray-50 flex items-center justify-between ${selected.includes(opt) ? 'bg-gray-50 text-gray-900 font-medium' : 'text-gray-600'}`}
                        >
                            <span className="truncate mr-2">{opt}</span>
                            {selected.includes(opt) && <Check size={14} className="text-indigo-600 flex-shrink-0" />}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

const BulkInsightManager: React.FC<BulkInsightManagerProps> = ({ 
  items, 
  results, 
  setResults, 
  status, 
  setStatus, 
  progress, 
  setProgress, 
  requestId, 
  setRequestId,
  onOpenChat
}) => {

  // Local UI State
  const [selectedCards, setSelectedCards] = useState<Set<string>>(new Set());

  // Multi-select filters (empty array means ALL)
  const [filterSymbols, setFilterSymbols] = useState<string[]>([]);
  const [filterIndicators, setFilterIndicators] = useState<string[]>([]);

  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // --- Actions ---

  const startExtraction = async () => {
    const stockSymbols = items.filter(i => i.type === 'STOCK').map(i => i.id);
    if (stockSymbols.length === 0) return;

    setStatus('initializing');
    setProgress({ completed: 0, total: stockSymbols.length });

    // We do NOT clear results here to allow "overlay" behavior if desired, 
    // or we could clear if we wanted a fresh start visually. 
    // For now, keeping data visible is better UX for "Refresh".

    const response = await initiateBulkInsightExtraction(stockSymbols);

    if (response && response.requestId) {
      setRequestId(response.requestId);
      setStatus('polling');
      setProgress({ completed: 0, total: response.totalStocks });
    } else {
      setStatus('error');
    }
  };

  // --- Auto Fetch Logic ---
  useEffect(() => {
    // Check if we need to auto-start
    const stockItems = items.filter(i => i.type === 'STOCK');
    const hasItems = stockItems.length > 0;
    const hasResults = Object.keys(results).length > 0;

    // Only auto-start if:
    // 1. We have stocks to track
    // 2. We have NO results yet (fresh load)
    // 3. Status is IDLE (not already running/error/completed)
    if (hasItems && !hasResults && status === 'idle') {
      startExtraction();
    }
  }, [items, status, results]); // Added items, status, results to dependencies to react when data loads

  // --- Polling Logic ---
  useEffect(() => {
    let intervalId: ReturnType<typeof setInterval>;

    const poll = async () => {
      if (!requestId || status !== 'polling') return;

      const data = await pollBulkInsightStatus(requestId);

      if (data) {
        setProgress({ completed: data.completedStocks, total: data.totalStocks });
        handleNewResults(data);

        if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks === data.totalStocks)) {
          setStatus('completed');
          setRequestId(null);
        }
      }
    };

    if (status === 'polling') {
      poll();
      intervalId = setInterval(poll, 5000);
    }

    return () => clearInterval(intervalId);
  }, [requestId, status]);

  const handleNewResults = (data: PollStatusResponse) => {
    setResults(prev => {
      const next = { ...prev };
      // Deep merge logic
      for (const [symbol, newItems] of Object.entries(data.results)) {
        const existingItems = next[symbol] || [];
        const mergedItems = [...existingItems];
        newItems.forEach(newItem => {
           const index = mergedItems.findIndex(i => i.indicatorName === newItem.indicatorName);
           if (index > -1) {
               mergedItems[index] = newItem;
           } else {
               mergedItems.push(newItem);
           }
        });
        next[symbol] = mergedItems;
      }
      return next;
    });
  };

  // --- Selection Logic ---

  const toggleCardSelection = (symbol: string, indicator: string) => {
      const key = `${symbol}|${indicator}`;
      const newSet = new Set(selectedCards);
      if (newSet.has(key)) newSet.delete(key);
      else newSet.add(key);
      setSelectedCards(newSet);
  };

  const handleAnalyzeSelection = () => {
      const selectedData: any[] = [];
      selectedCards.forEach(key => {
          const [sym, ind] = key.split('|');
          const item = results[sym]?.find(i => i.indicatorName === ind);
          if (item) {
              selectedData.push({ symbol: sym, indicator: ind, data: item.data });
          }
      });
      if (selectedData.length > 0) onOpenChat(selectedData);
  };

  // --- Render Helpers ---

  const flatItems = useMemo(() => {
      const flat: Array<{ symbol: string; item: InsightResultItem }> = [];
      Object.entries(results).forEach(([symbol, indicators]) => {
          // 1. Filter by Symbol (Multi-select)
          if (filterSymbols.length > 0 && !filterSymbols.includes(symbol)) {
              return;
          }

          indicators.forEach(item => {
              // 2. Filter by Indicator (Multi-select)
              if (filterIndicators.length > 0 && !filterIndicators.includes(item.indicatorName)) {
                  return;
              }
              flat.push({ symbol, item });
          });
      });
      return flat;
  }, [results, filterSymbols, filterIndicators]);

  const uniqueSymbols = Object.keys(results);
  const uniqueIndicators = Array.from(new Set(Object.values(results).flat().map(i => i.indicatorName)));

  const renderCardContent = (data: any) => {
      if (typeof data === 'string') {
          if (data.includes('<')) {
              return <div className="text-xs text-gray-400 italic">HTML Content - Click Chat to Analyze</div>;
          }
          return <div className="text-xs text-gray-600 line-clamp-4">{data}</div>;
      }
      if (typeof data === 'object') {
          return (
              <div className="text-[10px] font-mono text-gray-600 bg-gray-50 p-2 rounded overflow-hidden max-h-24">
                  <pre>{JSON.stringify(data, null, 2)}</pre>
              </div>
          );
      }
      return null;
  };

  if (items.filter(i => i.type === 'STOCK').length === 0) return null;

  return (
    <div className="space-y-4">
      {/* Control Bar */}
      <div className="bg-white rounded-xl border border-gray-200 p-4 flex flex-col xl:flex-row items-center justify-between gap-4 shadow-sm">
         <div className="flex items-center gap-4 w-full xl:w-auto">
             {/* View Toggle */}
             <div className="flex bg-gray-100 p-1 rounded-lg shrink-0">
               <button 
                  onClick={() => setViewMode('grid')}
                  className={`p-1.5 rounded-md transition-all ${viewMode === 'grid' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
                  title="Grid View"
               >
                 <LayoutGrid size={16} />
               </button>
               <button 
                  onClick={() => setViewMode('list')}
                  className={`p-1.5 rounded-md transition-all ${viewMode === 'list' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
                  title="List View"
               >
                 <List size={16} />
               </button>
             </div>

             <div className="h-6 w-px bg-gray-200 mx-1"></div>

             {/* Multi-Select Filters */}
             <div className="flex gap-2 w-full flex-wrap md:flex-nowrap">
                 <MultiSelect 
                    label="Stocks" 
                    options={uniqueSymbols} 
                    selected={filterSymbols} 
                    onChange={setFilterSymbols} 
                 />

                 <MultiSelect 
                    label="Indicators" 
                    options={uniqueIndicators} 
                    selected={filterIndicators} 
                    onChange={setFilterIndicators} 
                 />
             </div>
         </div>

         <div className="flex items-center gap-3 w-full xl:w-auto justify-end">
             {selectedCards.size > 0 && (
                 <button 
                    onClick={handleAnalyzeSelection}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-lg hover:bg-indigo-700 transition-colors shadow-sm whitespace-nowrap"
                 >
                     <MessageSquare size={16} />
                     Analyze Selected ({selectedCards.size})
                 </button>
             )}

            {status === 'polling' || status === 'initializing' ? (
                <div className="flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-700 rounded-lg text-sm whitespace-nowrap">
                    <Loader2 size={16} className="animate-spin" />
                    <span>
                      {status === 'initializing' ? 'Initializing...' : `${progress.completed}/${progress.total}`}
                    </span>
                </div>
            ) : (
                <button 
                    onClick={startExtraction}
                    className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-gray-100 rounded-lg transition-colors border border-transparent hover:border-gray-200"
                    title="Refresh Data"
                >
                    <RefreshCw size={20} />
                </button>
            )}
         </div>
      </div>

      {/* Loading Skeleton */}
      {flatItems.length === 0 && (status === 'initializing' || status === 'polling') && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-pulse">
             {[...Array(6)].map((_, i) => (
                 <div key={i} className="bg-white rounded-xl border border-gray-100 p-4 h-40 flex flex-col justify-between">
                    <div className="flex justify-between items-center mb-4">
                        <div className="h-4 bg-gray-200 rounded w-1/3"></div>
                        <div className="h-4 bg-gray-200 rounded w-4"></div>
                    </div>
                    <div className="space-y-2">
                        <div className="h-3 bg-gray-100 rounded w-full"></div>
                        <div className="h-3 bg-gray-100 rounded w-5/6"></div>
                        <div className="h-3 bg-gray-100 rounded w-4/6"></div>
                    </div>
                 </div>
             ))}
          </div>
      )}

      {/* Empty State */}
      {flatItems.length === 0 && status !== 'polling' && status !== 'initializing' && (
          <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
              <p className="text-gray-500">
                  {uniqueSymbols.length > 0 ? "No data matches your filters." : "No data loaded yet. Auto-fetching..."}
              </p>
          </div>
      )}

      {/* Grid vs List View */}
      <div className={`
        ${viewMode === 'grid' ? 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4' : 'flex flex-col gap-3'}
      `}>
          {flatItems.map(({ symbol, item }, idx) => {
              const cardKey = `${symbol}|${item.indicatorName}`;
              const isSelected = selectedCards.has(cardKey);

              return (
                  <div 
                    key={idx} 
                    className={`bg-white rounded-xl border transition-all duration-200 flex flex-col ${
                        isSelected ? 'border-indigo-500 shadow-md ring-1 ring-indigo-500' : 'border-gray-200 shadow-sm hover:shadow-md'
                    }`}
                  >
                      <div className="p-3 border-b border-gray-100 flex items-center justify-between bg-gray-50 rounded-t-xl">
                          <div className="flex items-center gap-2">
                              <span className="font-bold text-gray-800 text-sm">{symbol}</span>
                              <span className="text-xs text-gray-400">•</span>
                              <span className="text-xs font-medium text-gray-600 truncate max-w-[150px]" title={item.indicatorName}>
                                  {item.indicatorName}
                              </span>
                          </div>

                          <div className="flex items-center gap-2">
                              {item.success ? <CheckCircle size={14} className="text-green-500"/> : <AlertCircle size={14} className="text-red-500"/>}
                              <button 
                                onClick={() => toggleCardSelection(symbol, item.indicatorName)}
                                className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${
                                    isSelected ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-gray-300 text-transparent hover:border-indigo-400'
                                }`}
                              >
                                  <Check size={12} />
                              </button>
                          </div>
                      </div>

                      <div className="p-3 flex-1 overflow-hidden min-h-[80px]">
                          {item.success ? renderCardContent(item.data) : <div className="text-red-500 text-xs">Failed to load</div>}
                      </div>

                      {item.success && (
                          <div className="p-2 border-t border-gray-100 flex justify-end">
                              <button 
                                onClick={() => onOpenChat([{ symbol, indicator: item.indicatorName, data: item.data }])}
                                className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                              >
                                  <MessageSquare size={14} />
                                  Ask AI
                              </button>
                          </div>
                      )}
                  </div>
              );
          })}
      </div>
    </div>
  );
};

